<script>
function showError(message){document.getElementById('tool-error-text').textContent=message;document.getElementById('tool-error').style.display='flex';document.getElementById('tool-result').classList.remove('show');}
function clearError(){document.getElementById('tool-error').style.display='none';}
function runTool(){const base=parseFloat(document.getElementById('pot-base').value);const exp=parseFloat(document.getElementById('pot-exp').value);clearError();if(isNaN(base)||isNaN(exp)){showError('Preencha base e expoente com valores válidos.');return;}const valor=Math.pow(base,exp);if(!isFinite(valor)){showError('O resultado não pode ser exibido com os valores informados.');return;}document.getElementById('pot-valor').textContent=fmtNum(valor,6);document.getElementById('pot-baseinfo').textContent=fmtNum(base,6)+' ^ '+fmtNum(exp,6);document.getElementById('tool-detail').textContent='A conta representa a base multiplicada por ela mesma conforme o expoente.';showResult('tool-result');}function clearTool(){['pot-base','pot-exp'].forEach(id=>document.getElementById(id).value='');['pot-valor','pot-baseinfo'].forEach(id=>document.getElementById(id).textContent='-');document.getElementById('tool-detail').textContent='';document.getElementById('tool-result').classList.remove('show');clearError();}function copyTool(button){if(!document.getElementById('tool-result').classList.contains('show')){showError('Calcule a potência antes de copiar o resultado.');return;}copyToClipboard('Potência: '+document.getElementById('pot-valor').textContent,button);}
</script>
